mapper.select:
	/* wms-ctmaster-strategyplcm-sql-oracle.xml - selectStgPlcmList - 적치전략 조회 */
	SELECT *
	  FROM TWORK_MST_PLCM_STG_HD A
     INNER JOIN TWORK_MST_PLCM_STG_DT B
	  	ON A.CTKEY = B.CTKEY
	   AND A.PLCMSTGHDKEY = B.PLCMSTGHDKEY
     WHERE A.CTKEY = #{ctkey}
	   AND A.PLCMSTGDIVCD = #{plcmstgdivcd}

