mapper.select:
/* wms-ctmaster-strategyplcm-sql-oracle.xml - selectMstIcutxtype - 상품 단위 유형 조회 */
SELECT *
 FROM TWORK_MST_ICUTXTYPE
WHERE CTKEY = #{ctkey}
  AND OWKEY = #{owkey}
  AND ICKEY = #{ickey}
  AND ICUNITTYPECD = 'EA'

/* wms-ctmaster-strategyplcm-sql-oracle.xml - selectMstIcLckey - 상품 대표로케이션 조회 */
SELECT LCKEY
  FROM TWORK_MST_IC
 WHERE CTKEY = #{ctkey}
   AND ICKEY = #{ickey}

/* wms-ctmaster-strategyplcm-sql-oracle.xml - selectStgPlcmLckey - 로케이션 조회 */ WITH IV_SUM AS ( SELECT CTKEY, LCKEY FROM TWORK_INFO_IVATXLC GROUP BY CTKEY, LCKEY HAVING SUM(TOTQTY) > 0 ), REPLOC AS ( SELECT IC.CTKEY , IC.LCKEY AS REP_LCKEY , LC.RACKNO AS REP_RACK , LC.ROWNO AS REP_ROW , LC.TIERNO AS REP_TIER , LC.ZNKEY AS REP_ZNKEY , LC.ARKEY AS REP_ARKEY FROM TWORK_MST_IC IC LEFT JOIN TWORK_MST_LC LC ON IC.CTKEY = LC.CTKEY AND IC.LCKEY = LC.LCKEY WHERE IC.CTKEY = #{ctkey} AND IC.ICKEY = #{ickey} ), IC_CBM AS ( SELECT IC.CTKEY , IC.OWKEY , IC.ICKEY , EA_ICUT.VOL AS EA_CBM , INN_ICUT.VOL AS INN_CBM , CTN_ICUT.VOL AS CTN_CBM , INN_ICUT.ICUNITQTY AS INN_ICUNITQTY , CTN_ICUT.ICUNITQTY AS CTN_ICUNITQTY FROM TWORK_MST_IC IC INNER JOIN TWORK_MST_ICUTXTYPE EA_ICUT ON IC.CTKEY = EA_ICUT.CTKEY AND IC.OWKEY = EA_ICUT.OWKEY AND IC.ICKEY = EA_ICUT.ICKEY AND EA_ICUT.ICUNITTYPECD = 'EA' INNER JOIN TWORK_MST_ICUTXTYPE INN_ICUT ON IC.CTKEY = INN_ICUT.CTKEY AND IC.OWKEY = INN_ICUT.OWKEY AND IC.ICKEY = INN_ICUT.ICKEY AND INN_ICUT.ICUNITTYPECD = 'INN' INNER JOIN TWORK_MST_ICUTXTYPE CTN_ICUT ON IC.CTKEY = CTN_ICUT.CTKEY AND IC.OWKEY = CTN_ICUT.OWKEY AND IC.ICKEY = CTN_ICUT.ICKEY AND CTN_ICUT.ICUNITTYPECD = 'CTN' LEFT JOIN TWORK_MST_LC LC ON IC.CTKEY = LC.CTKEY AND IC.LCKEY = LC.LCKEY WHERE IC.CTKEY = #{ctkey} AND IC.ICKEY = #{ickey} ), DAY_AVG AS ( SELECT A.CTKEY , A.OWKEY , A.ICKEY , A.CRITDAY , A.OBQTY , A.DAYAVGOBQTY , A.CNVRTOBQTY , EA_ICUT.VOL AS EA_CBM , INN_ICUT.VOL AS INN_CBM , CTN_ICUT.VOL AS CTN_CBM , INN_ICUT.ICUNITQTY AS INN_ICUNITQTY , CTN_ICUT.ICUNITQTY AS CTN_ICUNITQTY , ROUND((A.CNVRTOBQTY / CTN_ICUT.ICUNITQTY * CTN_ICUT.VOL),6) AS CNVRTCBM , CASE WHEN (SELECT COUNT(1) FROM TWORK_MST_LC LC WHERE LC.CTKEY = #{ctkey} AND LC.ZNKEY IN ('H','P') AND ROUND((A.CNVRTOBQTY / CTN_ICUT.ICUNITQTY * CTN_ICUT.VOL),6) BETWEEN CBMSTARTRNG AND CBMCLOSRNG ) > 0 THEN 'Y' ELSE 'N' END AS PLT_ABLE_YN FROM TWORK_INFO_DAY_AVG_OBQTY A INNER JOIN ( SELECT CTKEY , OWKEY , ICKEY , MAX(CRITDAY) AS CRITDAY FROM TWORK_INFO_DAY_AVG_OBQTY WHERE CTKEY = #{ctkey} AND ICKEY = #{ickey} GROUP BY CTKEY , OWKEY , ICKEY ) B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.ICKEY = B.ICKEY AND A.CRITDAY = B.CRITDAY INNER JOIN TWORK_MST_ICUTXTYPE EA_ICUT ON A.CTKEY = EA_ICUT.CTKEY AND A.OWKEY = EA_ICUT.OWKEY AND A.ICKEY = EA_ICUT.ICKEY AND EA_ICUT.ICUNITTYPECD = 'EA' INNER JOIN TWORK_MST_ICUTXTYPE INN_ICUT ON A.CTKEY = INN_ICUT.CTKEY AND A.OWKEY = INN_ICUT.OWKEY AND A.ICKEY = INN_ICUT.ICKEY AND INN_ICUT.ICUNITTYPECD = 'INN' INNER JOIN TWORK_MST_ICUTXTYPE CTN_ICUT ON A.CTKEY = CTN_ICUT.CTKEY AND A.OWKEY = CTN_ICUT.OWKEY AND A.ICKEY = CTN_ICUT.ICKEY AND CTN_ICUT.ICUNITTYPECD = 'CTN' WHERE A.CTKEY = #{ctkey} AND A.ICKEY = #{ickey} ) SELECT TT.* FROM ( SELECT ROW_NUMBER() OVER(ORDER BY PRIORITY ASC, DISTANCE ASC, ZNKEY ASC, ARKEY ASC
, ${orderby1} ${sort1}
, ${orderby2} ${sort2}
, ${orderby3} ${sort3}
) AS RN , T.* FROM ( SELECT LC.* , AR.ARNM , ZN.ZNNM , LCTYP.CTCDDTNM AS LCSTORGTYPENM , LCDS.DSBTGRADECD , CASE WHEN LC.LCKEY = R.REP_LCKEY THEN 1 ELSE 2 END AS PRIORITY , CASE WHEN R.REP_LCKEY IS NOT NULL THEN CASE WHEN LC.RACKNO = R.REP_RACK AND LC.ROWNO = R.REP_ROW THEN ABS(LC.TIERNO::INTEGER - R.REP_TIER::INTEGER) WHEN LC.RACKNO = R.REP_RACK THEN ABS(LC.ROWNO::INTEGER - R.REP_ROW::INTEGER) * 100 + ABS(LC.TIERNO::INTEGER - R.REP_TIER::INTEGER) ELSE ABS(LC.RACKNO::INTEGER - R.REP_RACK::INTEGER) * 10000 + ABS(LC.ROWNO::INTEGER - R.REP_ROW::INTEGER) * 100 + ABS(LC.TIERNO::INTEGER - R.REP_TIER::INTEGER) END ELSE 999999 END AS DISTANCE /* 거리 계산: RACKNO 동일 > ROWNO 동일 > TIERNO 차이 */ FROM TWORK_MST_LC LC INNER JOIN TWORK_MST_AR AR ON LC.CTKEY = AR.CTKEY AND LC.ZNKEY = AR.ZNKEY AND LC.ARKEY = AR.ARKEY INNER JOIN TWORK_MST_ZN ZN ON LC.CTKEY = ZN.CTKEY AND LC.ZNKEY = ZN.ZNKEY LEFT OUTER JOIN TWORK_MST_LC_DSBTGRADE LCDS ON LC.CTKEY = LCDS.CTKEY AND LC.LCKEY = LCDS.LCKEY LEFT OUTER JOIN TWORK_MST_CTCD_DT LCTYP /* 로케이션유형 */ ON LCTYP.CTKEY = LC.CTKEY AND LCTYP.CTCDHDKEY = 'LCSTORGTYPECD' AND LCTYP.CTCDDTKEY = LC.LCSTORGTYPECD AND LCTYP.LAKEY = 'KOR' LEFT JOIN IV_SUM IVS ON LC.CTKEY = IVS.CTKEY AND LC.LCKEY = IVS.LCKEY LEFT JOIN REPLOC R ON LC.CTKEY = R.CTKEY AND LC.LCKEY = R.REP_LCKEY LEFT JOIN IC_CBM ICBM ON LC.CTKEY = ICBM.CTKEY LEFT JOIN DAY_AVG DAVG ON LC.CTKEY = DAVG.CTKEY WHERE IVS.LCKEY IS NULL
AND ZN.ZNTYPECD = '10' AND ZN.ZNKEY IN ('H','P') -- AND (R.REP_LCKEY IS NULL OR (REP_ZNKEY = ZN.ZNKEY AND REP_ARKEY = AR.ARKEY)) /* 약 2일간의 입고예정정보에 해당하는 다른 상품의 대표로케이션은 제외처리 */ AND LC.LCKEY NOT IN ( SELECT IC.LCKEY FROM TWORK_INFO_IB_HD IH INNER JOIN TWORK_INFO_IB_DT ID ON IH.CTKEY = ID.CTKEY AND IH.OWKEY = ID.OWKEY AND IH.IBHDKEY = ID.IBHDKEY INNER JOIN TWORK_MST_IC IC ON ID.CTKEY = IC.CTKEY AND ID.OWKEY = IC.OWKEY AND ID.ICKEY = IC.ICKEY WHERE IH.CTKEY = #{ctkey} AND IH.OWKEY = #{owkey} AND IH.IBHDTYPECD = '30' AND IH.IBEXPCTDATE BETWEEN TO_CHAR(CURRENT_TIMESTAMP - INTERVAL '2 days','YYYYMMDD')||'000000' AND TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDD')||'000000' AND ( ID.IBDTSTATUSCD = '00' OR ID.PLCMSTATUSCD = '00' ) AND ID.IBDTSTATUSCD NOT IN ('91','92','99') AND ID.ICKEY <> #{ickey} AND IC.LCKEY IS NOT NULL GROUP BY IC.LCKEY ) AND COALESCE(COALESCE(DAVG.CNVRTCBM, ICBM.CTN_CBM), 0) BETWEEN (CASE WHEN COALESCE(DAVG.PLT_ABLE_YN, 'Y') = 'Y' THEN LC.CBMSTARTRNG ELSE COALESCE(COALESCE(DAVG.CNVRTCBM, ICBM.CTN_CBM), 0) END) AND (CASE WHEN COALESCE(DAVG.PLT_ABLE_YN, 'Y') = 'Y' THEN LC.CBMCLOSRNG ELSE COALESCE(COALESCE(DAVG.CNVRTCBM, ICBM.CTN_CBM), 0) END) AND LC.ZNKEY IN ( SELECT (CASE WHEN COALESCE(DAVG.PLT_ABLE_YN, 'Y') = 'Y' THEN 'H' ELSE 'P' END) AS ZNKEY UNION ALL SELECT 'P' AS ZNKEY )
AND ZN.ZNTYPECD = '10' AND ZN.ZNKEY = 'P'
) T WHERE 1=1
AND LCTYPECD IN
#{listLcType}
AND LCKEY IN
#{listIncludeLc}
AND LCKEY NOT IN
#{listExcludeLc}
AND ARKEY IN
#{listIncludeArea}
AND ARKEY NOT IN
#{listExcludeArea}
AND ICPLCMDIVCD = #{icplcmdivcd}
AND ICARDIVCD = #{icardivcd}
AND DSBTGRADECD = #{dsbtgradecd}
AND #{vol} BETWEEN CBMSTARTRNG AND CBMCLOSRNG
AND LCKEY NOT IN
#{listIcLcRecom}
AND LCSTORGTYPECD = #{lcstorgtypecd}
AND ARKEY = #{arkey}
AND ALTMTALENO = #{altmtaleno}
AND ALTMTARNO = #{altmtarno}
AND LCKEY = #{lckey}
ORDER BY PRIORITY ASC , DISTANCE ASC , ZNKEY ASC , ARKEY ASC
, ${orderby1} ${sort1}
, ${orderby2} ${sort2}
, ${orderby3} ${sort3}
) TT
WHERE TT.RN = 1
